463:      * Get a list of batches which have been sitting in the accumulator too long and need to be expired.
464:      */
465:     public List<ProducerBatch> expiredBatches(long now) {
466:         List<ProducerBatch> expiredBatches = new ArrayList<>();
467:         for (TopicInfo topicInfo : topicInfoMap.values()) {
468:             for (Deque<ProducerBatch> deque : topicInfo.batches.values()) {
469:                 // expire the batches in the order of sending
470:                 synchronized (deque) {
471:                     while (!deque.isEmpty()) {
472:                         ProducerBatch batch = deque.getFirst();
473:                         if (batch.hasReachedDeliveryTimeout(deliveryTimeoutMs, now)) {
474:                             deque.poll();
475:                             batch.abortRecordAppends();
476:                             expiredBatches.add(batch);
477:                         } else {
478:                             maybeUpdateNextBatchExpiryTime(batch);
479:                             break;
480:                         }
481:                     }
482:                 }
483:             }
484:         }
485:         return expiredBatches;
486:     }
